// Generate probe queries for each site
const sites = $input.all();
const probes = [];

for (const site of sites) {
  const s = site.json;
  const city = s.target_city || s.city || '';
  const state = s.target_state || s.state || '';
  const name = s.business_name || '';
  const kw = s.primary_keyword || 'tattoo shop';

  const queries = [
    `best ${kw} in ${city} ${state}`,
    `top rated tattoo artists in ${city}`,
    `${name} ${city} reviews`,
    `where to get a tattoo in ${city} ${state}`,
    `tattoo shops near me ${city}`
  ];

  for (const query of queries) {
    for (const engine of ['chatgpt', 'perplexity', 'gemini']) {
      probes.push({ json: { site_id: s.id, business_name: name, domain: s.domain, phone: s.phone, address: s.address, query, engine } });
    }
  }
}

return probes;

