// Analyze AI response for mentions of the business
const probe = $('Rate Limiter').first().json;
const response = $json.choices?.[0]?.message?.content || $json.error?.message || '';
const name = probe.business_name.toLowerCase();
const domain = (probe.domain || '').toLowerCase().replace(/^https?:\/\//, '').replace(/\/$/, '');

const mentioned = response.toLowerCase().includes(name) || response.toLowerCase().includes(domain);

// NAP accuracy check
let napAccurate = null;
if (mentioned) {
  const hasPhone = probe.phone ? response.includes(probe.phone) || response.includes(probe.phone.replace(/-/g, '')) : null;
  const hasAddress = probe.address ? response.toLowerCase().includes(probe.address.toLowerCase()) : null;
  napAccurate = hasPhone || hasAddress;
}

// Sentiment (basic)
let sentiment = null;
if (mentioned) {
  const positive = /recommend|great|excellent|best|top|amazing|skilled|talented/i;
  const negative = /avoid|poor|bad|unprofessional|overpriced/i;
  if (positive.test(response)) sentiment = 'positive';
  else if (negative.test(response)) sentiment = 'negative';
  else sentiment = 'neutral';
}

return [{ json: {
  site_id: probe.site_id,
  engine: probe.engine,
  query: probe.query,
  mentioned,
  nap_accurate: napAccurate,
  sentiment,
  response_snippet: response.substring(0, 500),
  checked_at: new Date().toISOString()
}}];
